import{_ as e,o as l,c as i,ai as r}from"./chunks/framework.DjxHwWNk.js";const m=JSON.parse('{"title":"Места","description":"Каталог ключевых мест уральского рока в Екатеринбурге.","frontmatter":{"title":"Места","description":"Каталог ключевых мест уральского рока в Екатеринбурге.","outline":"deep"},"headers":[],"relativePath":"places/index.md","filePath":"places/index.md"}'),h={name:"places/index.md"};function s(t,a,o,d,n,p){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="места-уральского-рока" tabindex="-1">Места уральского рока <a class="header-anchor" href="#места-уральского-рока" aria-label="Permalink to “Места уральского рока”">​</a></h1><p>В этом разделе собраны ключевые точки Екатеринбурга, связанные с историей Свердловского рок-клуба, уральского андеграунда, репетиционных баз, фестивалей и биографий музыкантов.</p><h2 id="каталог-мест" tabindex="-1">Каталог мест <a class="header-anchor" href="#каталог-мест" aria-label="Permalink to “Каталог мест”">​</a></h2><h3 id="центральные-площадки" tabindex="-1">Центральные площадки <a class="header-anchor" href="#центральные-площадки" aria-label="Permalink to “Центральные площадки”">​</a></h3><ul><li><p><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a><br> Официальная колыбель Свердловского рок-клуба. Именно здесь 15 марта 1986 года открылся СРК.</p></li><li><p><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a><br> Одна из главных концертных площадок Свердловска и место крупных фестивалей рок-клуба.</p></li><li><p><a href="/Knowledge-Base/places/dk-avtomobilistov.html">Свято-Троицкий кафедральный собор / бывший ДК Автомобилистов</a><br> Место первого рок-фестиваля в Свердловске в 1981 году.</p></li></ul><h3 id="университеты-и-студенческие-места" tabindex="-1">Университеты и студенческие места <a class="header-anchor" href="#университеты-и-студенческие-места" aria-label="Permalink to “Университеты и студенческие места”">​</a></h3><ul><li><p><a href="/Knowledge-Base/places/urfu-rtf.html">УрФУ, Радиофак / РТФ УПИ</a><br> Место, связанное с рождением группы «Агата Кристи».</p></li><li><p><a href="/Knowledge-Base/places/obschezhitie-11-urfu.html">Общежитие № 11 УрФУ</a><br> Студенческое пространство, связанное с ранней историей «Агаты Кристи».</p></li><li><p><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a><br> Легендарная репетиционная база свердловского андеграунда.</p></li></ul><h3 id="школы-и-культурные-точки" tabindex="-1">Школы и культурные точки <a class="header-anchor" href="#школы-и-культурные-точки" aria-label="Permalink to “Школы и культурные точки”">​</a></h3><ul><li><p><a href="/Knowledge-Base/places/dk-mzhk-molodezhny.html">ДК МЖК / Центр культуры «Молодёжный»</a><br> Одна из важных ранних площадок группы «Чайф».</p></li><li><p><a href="/Knowledge-Base/places/school-36.html">Школа № 36</a><br> Место, связанное с юностью основателей «Чайфа».</p></li><li><p><a href="/Knowledge-Base/places/school-2.html">Школа № 2</a><br> Школа, связанная с Алексеем Балабановым и Евгением Горенбургом.</p></li></ul><h3 id="личные-адреса" tabindex="-1">Личные адреса <a class="header-anchor" href="#личные-адреса" aria-label="Permalink to “Личные адреса”">​</a></h3><ul><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a><br> «Заколдованный дом», связанный со студенческими годами Александра Башлачёва.</li></ul><h2 id="как-пользоваться-разделом" tabindex="-1">Как пользоваться разделом <a class="header-anchor" href="#как-пользоваться-разделом" aria-label="Permalink to “Как пользоваться разделом”">​</a></h2><p>Каждая страница места содержит:</p><ul><li>историческую справку;</li><li>адрес;</li><li>связанных музыкантов, режиссёров и организаторов;</li><li>связанные группы;</li><li>современный статус;</li><li>роль места в Год уральского рока — 2026;</li><li>ссылки на маршруты и соседние точки.</li></ul>',14)])])}const f=e(h,[["render",s]]);export{m as __pageData,f as default};
